  width: 100%;
  padding: 16px 12px 6px;
  border: 2px solid #d1d5db;
  border-radius: 8px;
  font-size: 1rem;
  outline: none;
}
.field label {
  position: absolute;
  left: 12px;
  top: 50%;
  transform: translateY(-50%);
  color: #9ca3af;
  pointer-events: none;
  transition: all 0.2s ease;
}
/* ラベルが浮き上がる条件 */
.field input:focus + label,
.field input:not(:placeholder-shown) + label {
  top: 6px;
  transform: none;
  font-size: 0.75rem;
  color: #3b82f6;
}

