const form = document.querySelector('form');

form.addEventListener('submit', async (e) => {
  e.preventDefault();
  const formData = new FormData(form);

  try {
    // JSONで送信
    const response = await fetch('/api/submit', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(Object.fromEntries(formData)),
    });

    // または multipart/form-data で送信（ファイル含む場合）
    // const response = await fetch('/api/upload', {
    //   method: 'POST',
    //   body: formData,  // Content-Type自動設定
    // });

    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const result = await response.json();
    showSuccess('送信完了');
  } catch (err) {
    showError('送信失敗: ' + err.message);
  }
});

// リアルタイムバリデーションの実装
const fields = document.querySelectorAll('.validate-field');

fields.forEach(field => {
  const message = field.nextElementSibling; // エラーメッセージ要素

  field.addEventListener('input', () => {
    field.classList.add('touched');
    if (field.validity.valid) {
      message.textContent = '';
      field.setAttribute('aria-invalid', 'false');
    } else {
      message.textContent = field.validationMessage;
      field.setAttribute('aria-invalid', 'true');
    }
  });

  // フォーカスが外れた時にもチェック
  field.addEventListener('blur', () => {
    field.classList.add('touched');
  });
});

/* CSS */
.validate-field.touched:invalid {
  border-color: #ef4444;
}
.validate-field:valid {
  border-color: #22c55e;
}
.error-message {
  color: #ef4444;
  font-size: 0.8rem;
}

class MultiStepForm {
  constructor(formElement, steps) {
    this.form = formElement;
    this.steps = steps;
    this.currentStep = 0;
  }

  showStep(index) {
    this.steps.forEach((step, i) => {
      step.style.display = i === index ? 'block' : 'none';
    });
    this.updateProgress();
  }

  nextStep() {
    const currentFields = this.steps[this.currentStep]
      .querySelectorAll('input, select, textarea');
    // 現ステップのバリデーション
    const valid = [...currentFields].every(f => f.reportValidity());
    if (valid && this.currentStep < this.steps.length - 1) {
      this.saveToSession();
      this.currentStep++;
      this.showStep(this.currentStep);
    }
  }

  prevStep() {
    if (this.currentStep > 0) {
      this.currentStep--;
      this.showStep(this.currentStep);
    }
  }

  saveToSession() {
    const data = new FormData(this.form);
    sessionStorage.setItem('form-data',
      JSON.stringify(Object.fromEntries(data)));
  }
}
